116	  it.todo("claim on steel sword, enchantment 9, damage 1000 G: payout 400 G (50 % first, then deductible)");
117	
118	  // --- Claim: dragon-material clause ---
119	  it.todo("claim on dragon-material sword, enchantment 5, damage 800 G: payout 700 G (full reimbursement, then deductible)");
120	
121	  // --- Claim: both clauses — 50 % rule wins ---
122	  it.todo("claim on dragon-material sword, enchantment 9, damage 1000 G: payout 400 G (50 % rule wins, then deductible: 500 − 100)");
123	  it.todo("claim on dragon-material sword, enchantment exactly 8, damage 1000 G: payout 400 G (high-enchantment clause applies, then deductible)");
124	
125	  // --- Claim: deductible per damage event (multi-item single incident) ---
126	  it.todo("claim on sword and amulet (single dragon attack), damages [500, 300]: payout 600 G (deductible applies once per damaged item)");
127	
128	  // --- Claim: cap = 2 × insurance sum ---
129	  it.todo("policy with sword and amulet has insurance sum 1600 G; cap is 3200 G");
130	  it.todo("policy with cursed sword (modifiers make premium 165 G) has cap 2000 G — modifiers do not raise the cap");
131	  it.todo("policy with sword and 3 runes (block) has insurance sum 1750 G — block discount affects premium only, not the insurance sum");
132	
133	  // --- Claim: cap exhaustion across successive claims ---
134	  it.todo("sword policy (cap 2000 G), first claim 1500 G: payout 1400 G, remainingCap 600 G");
135	  it.todo("sword policy (cap 2000 G), second successive claim 1500 G: payout 600 G, remainingCap 0 G (reduced to remaining cap)");
136	
137	  // --- Claim: multiple items of the same type ---
138	  it.todo("policy with two swords has insurance sum 2000 G and cap 4000 G");
